  ('diplomatic-9e854390-moex-00459', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項陳述不是國際關係學中建構主義的主要內涵？', '["國際體系中的無政府狀態是各個國家對國際體系的認知與各國依據該認知來互動所造就而成的", "價值觀與意識形態對國家的行為會造成影響", "國際法對國家外交決策與行為沒有實質影響", "建構主義重視研究國際中改變價值觀與規範的各種國家舉措"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "af3d450287d9", "answer_pdf_sha1": "337ad6ed36e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00460', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '以下陳述那一項不符合國際關係學中自由主義的主要內涵？', '["國際體系必須依賴霸權來維持體系的穩定，否則不可能擺脫無政府的狀態", "透過制度的建立，國際之間可以達成長久合作與相互信任", "國際建制（或稱國際制度）可以為國際體系帶來集體安全", "國家並不是國際體系中唯一的行為者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "af3d450287d9", "answer_pdf_sha1": "337ad6ed36e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00461', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '對國際政治學中的現實主義來說，權力平衡是指某一國家或是多個國家的集合，運用權力來抗衡 另一個國家或是國家集合，以期阻止受抗衡國家或國家集合的擴張之過程。請問以下那一案例不 能被歸類為權力平衡？', '["在拿破崙戰爭中，英國與西班牙的合作", "聯合國及其相關制度之建立", "目前美國的印太戰略", "北約組織與華沙公約組織之建立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:31+00:00", "source_pdf_sha1": "af3d450287d9", "answer_pdf_sha1": "337ad6ed36e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
